import { create } from 'zustand';
import { persist } from 'zustand/middleware';

interface CartItem {
  id: string;
  name: string;
  price: number;
  quantity: number;
}

interface CartState {
  items: CartItem[];
  addItem: (item: CartItem) => void;
  removeItem: (id: string) => void;
  syncFromStorage: () => void;
}

export const useCartStore = create<CartState>()(
  persist(
    (set, get) => ({
      items: [],

      addItem: (item) => {
        const existing = get().items.find(i => i.id === item.id);
        if (existing) {
          set({
            items: get().items.map(i =>
              i.id === item.id ? { ...i, quantity: i.quantity + 1 } : i
            )
          });
        } else {
          set({ items: [...get().items, { ...item, quantity: 1 }] });
        }
      },

      removeItem: (id) => {
        set({ items: get().items.filter(i => i.id !== id) });
      },

      syncFromStorage: () => {
        const stored = localStorage.getItem('cart-storage');
        if (stored) {
          const { state } = JSON.parse(stored);
          set({ items: state.items });
        }
      }
    }),
    { name: 'cart-storage' }
  )
);

// Dans le composant racine (App.tsx ou un hook personnalisé)
import { useEffect } from 'react';
import { useCartStore } from './cartStore';

export function useCartSync() {
  const syncFromStorage = useCartStore((state) => state.syncFromStorage);

  useEffect(() => {
    const handleStorageChange = (e: StorageEvent) => {
      if (e.key === 'cart-storage') {
        syncFromStorage();
      }
    };

    window.addEventListener('storage', handleStorageChange);
    return () => window.removeEventListener('storage', handleStorageChange);
  }, [syncFromStorage]);
}

// Dans App.tsx
function App() {
  useCartSync(); // Active la synchronisation cross-tab
  return <div>...</div>;
}
